    <script>
        // 使用日志系统记录所有初始化尝试
        window.PetLogger.info('INIT', '========== 脚本开始执行 ==========');
        window.PetLogger.info('INIT', 'window.petInitDone 状态', window.petInitDone);

        // 如果已经有虚拟宠物实例，直接跳过
